         return $this->toDateTime();
     }

+    /**
+     * Get a colloquial relative calendar string such as "today", "yesterday", "tomorrow",
+     * "last Monday", or "next Friday" relative to now (or the given reference date).
+     *
+     * Uses the locale translation keys diff_today, diff_yesterday, diff_tomorrow, calendar_last_day,
+     * and calendar_next_day when available, falling back to English.
+     *
+     * @param \Carbon\CarbonInterface|\DateTimeInterface|string|null $referenceDate date to compare against (default: now)
+     */
+    public function toRelativeCalendarString($referenceDate = null): string
+    {
+        /** @var CarbonInterface $this */
+        $reference = $referenceDate === null
+            ? $this->nowWithSameTz()
+            : $this->resolveCarbon($referenceDate);
+
+        if ($this->toDateString() === $reference->toDateString()) {
+            $key = 'diff_today';
+            $translation = $this->getTranslationMessage($key) ?? $key;
+            return $translation === $key ? 'today' : $translation;
+        }
+
+        $yesterday = $reference->copy()->subDay();
+        if ($this->toDateString() === $yesterday->toDateString()) {
+            $key = 'diff_yesterday';
+            $translation = $this->getTranslationMessage($key) ?? $key;
+            return $translation === $key ? 'yesterday' : $translation;
+        }
+
+        $tomorrow = $reference->copy()->addDay();
+        if ($this->toDateString() === $tomorrow->toDateString()) {
+            $key = 'diff_tomorrow';
+            $translation = $this->getTranslationMessage($key) ?? $key;
+            return $translation === $key ? 'tomorrow' : $translation;
+        }
+
+        $dayName = $this->getTranslatedDayName();
+        if ($this < $reference) {
+            $keyTemplate = 'calendar_last_day';
+            $fallback = 'last :day';
+        } else {
+            $keyTemplate = 'calendar_next_day';
+            $fallback = 'next :day';
+        }
+        $template = $this->getTranslationMessage($keyTemplate) ?? $fallback;
+        return str_replace(':day', $dayName, $template);
+    }
+
